class Solution(object):
    def separateSquares(self, squares):
        total = sum(float(l * l) for _, _, l in squares)

        def area_below(y):
            s = 0.0
            for _, yi, li in squares:
                if y <= yi:
                    pass  # entire square above
                elif y >= yi + li:
                    s += li * li  # entire square below
                else:
                    s += (y - yi) * li  # partial
            return s

        lo = float(min(y for _, y, _ in squares))
        hi = float(max(y + l for _, y, l in squares))

        for _ in range(100):  # 100 iterations gives ~1e-30 precision
            mid = (lo + hi) / 2.0
            below = area_below(mid)
            if below < total / 2.0:
                lo = mid
            else:
                hi = mid

        return (lo + hi) / 2.0
